/**
 * @summary Bakım kayıtlarını listele
 */
export const getListMaintenanceUrl = (params?: ListMaintenanceParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/maintenance?${stringifiedParams}`
    : `/api/maintenance`;
};

export const listMaintenance = async (
  params?: ListMaintenanceParams,
  options?: RequestInit,
): Promise<MaintenanceRecord[]> => {
  return customFetch<MaintenanceRecord[]>(getListMaintenanceUrl(params), {
    ...options,
    method: "GET",
  });
};

